import { createClient, type SupabaseClient } from '@supabase/supabase-js';
import type { Database } from './types';
import {
  SUPABASE_KEY,
  SUPABASE_URL,
  getSupabaseAnonKeyOverride,
  getSupabaseUrlOverride,
} from '@/config/supabaseConfig';

const urlOverride = getSupabaseUrlOverride();
const keyOverride = getSupabaseAnonKeyOverride();

const resolvedUrl = urlOverride || SUPABASE_URL;
const resolvedKey = keyOverride || SUPABASE_KEY;

export const supabaseConfigError: string | null =
  !resolvedUrl || !resolvedKey
    ? 'Supabase URL või anon key puudub (env + fallback tühjad).'
    : null;

if (supabaseConfigError) {
  console.error(`[supabase] ${supabaseConfigError}`);
}

// Import the supabase client like this:
// import { supabase } from "@/integrations/supabase/client";

function buildConfigErrorProxy(message: string): SupabaseClient<Database> {
  const throwErr = () => {
    throw new Error(`Supabase client unavailable: ${message}`);
  };
  return new Proxy({} as SupabaseClient<Database>, {
    get: throwErr,
    apply: throwErr,
  });
}

export const supabase: SupabaseClient<Database> = supabaseConfigError
  ? buildConfigErrorProxy(supabaseConfigError)
  : createClient<Database>(resolvedUrl, resolvedKey, {
      auth: {
        storage: localStorage,
        persistSession: true,
        autoRefreshToken: true,
      },
    });
